module Compare(
    input  [31:0] A,
    input  [31:0] B,
    output EQ,
    output GZ,
    output LZ,
    output GEZ,
    output LEZ
    );
    wire   Inv_ZeroA = (A == 32'b0);
    assign EQ  = ( A == B);
    assign GZ  = (~A[31] & ~Inv_ZeroA);
    assign LZ  =   A[31];
    assign GEZ =  ~A[31];
    assign LEZ = ( A[31] |  Inv_ZeroA);
endmodule
